   380→        this.selectedSquare = null;
   381→        this.validMoves = [];
   382→        this.lastMove = null;
   383→        this.hoveredSquare = null;
   384→        this.checkAnimation = null;
   385→        this.gameOverAnimation = null;
   386→        this.animationManager.clear();
   387→    }
   388→}
